package com.wjx871.population.export;import com.wjx871.population.audit.*;import java.time.*;import lombok.RequiredArgsConstructor;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.*;
@Service @RequiredArgsConstructor public class ExportCleanupService {private final ExportMapper mapper;private final ExportProperties props;private final Clock clock;private final ExportCleanupWorker worker;@Scheduled(cron="${export.cleanup-cron:0 30 2 * * *}")public void scheduled(){runNow();}public int runNow(){var rows=mapper.expiredCandidates(LocalDateTime.now(clock).minusDays(props.getFileRetentionDays()));rows.forEach(x->worker.cleanup(x.getExportLogId()));return rows.size();}}
@Service @RequiredArgsConstructor class ExportCleanupWorker {private final ExportMapper mapper;private final ExportFileService files;private final OperationLogMapper audit;@Transactional(propagation=Propagation.REQUIRES_NEW)public void cleanup(Long id){DataExportLog x=mapper.lockLog(id).orElse(null);if(x==null||!"COMPLETED".equals(x.getStatus()))return;try{files.delete(x.getStoredFilename());if(mapper.expireLog(id,x.getVersion())==0)return;audit.insert(OperationLog.builder().operationType("DATA_EXPORT_CLEANUP").moduleName("EXPORT").operationResult("SUCCESS").detail("expired export "+x.getExportNo()).build());}catch(Exception e){throw new IllegalStateException("导出文件清理失败: "+x.getExportNo(),e);}}}
